    var wait_ctx = initContext(&server, null, &registry, null);
    var signal_ctx = initContext(&server, null, &registry, null);
    const wait_args = [_][]const u8{"blocking-channel"};
    var blocking_wait = BlockingWait{
        .registry = &registry,
        .ctx = &wait_ctx,
        .args = wait_args[0..],
